import (
	"bytes"
	"testing"

	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"
)

func TestLineEnding(t *testing.T) {
	RegisterFailHandler(Fail)
	RunSpecs(t, "Line Ending Suite")
}

var _ = Describe("CRLFWriter", func() {
	var buffer *bytes.Buffer
	var writer *CRLFWriter

	BeforeEach(func() {
		buffer = &bytes.Buffer{}
		writer = &CRLFWriter{writer: buffer}
	})

	Describe("Write", func() {
		It("converts single LF to CRLF", func() {
			n, err := writer.Write([]byte("hello\n"))
			Expect(err).ToNot(HaveOccurred())
			Expect(n).To(Equal(6))
			Expect(buffer.String()).To(Equal("hello\r\n"))
		})

		It("preserves existing CRLF", func() {
			n, err := writer.Write([]byte("hello\r\n"))
			Expect(err).ToNot(HaveOccurred())
			Expect(n).To(Equal(8))
			Expect(buffer.String()).To(Equal("hello\r\n"))
		})

		It("converts multiple LF to CRLF", func() {
			n, err := writer.Write([]byte("hello\nworld\n"))
			Expect(err).ToNot(HaveOccurred())
			Expect(n).To(Equal(12))
			Expect(buffer.String()).To(Equal("hello\r\nworld\r\n"))
		})

		It("handles mixed LF and CRLF", func() {
			n, err := writer.Write([]byte("hello\r\nworld\n"))
			Expect(err).ToNot(HaveOccurred())
			Expect(n).To(Equal(13))
			Expect(buffer.String()).To(Equal("hello\r\nworld\r\n"))
		})

		It("handles empty writes", func() {
			n, err := writer.Write([]byte{})
			Expect(err).ToNot(HaveOccurred())
			Expect(n).To(Equal(0))
			Expect(buffer.String()).To(Equal(""))
		})

		It("handles standalone CR", func() {
			n, err := writer.Write([]byte("hello\rworld"))
			Expect(err).ToNot(HaveOccurred())
			Expect(n).To(Equal(11))
			Expect(buffer.String()).To(Equal("hello\rworld"))
		})

		It("handles CRLF split across writes", func() {
			// First write ends with \r
			n1, err1 := writer.Write([]byte("hello\r"))
			Expect(err1).ToNot(HaveOccurred())
			Expect(n1).To(Equal(6))
			Expect(buffer.String()).To(Equal("hello\r"))

			// Second write starts with \n
			n2, err2 := writer.Write([]byte("\nworld"))
			Expect(err2).ToNot(HaveOccurred())
			Expect(n2).To(Equal(6))
			// The \n should not be converted to \r\n because it's preceded by \r
			Expect(buffer.String()).To(Equal("hello\r\nworld"))
		})

		It("handles LF split across writes", func() {
			// First write with content and no trailing newline
			n1, err1 := writer.Write([]byte("hello"))
			Expect(err1).ToNot(HaveOccurred())
			Expect(n1).To(Equal(5))
			Expect(buffer.String()).To(Equal("hello"))

			// Second write with \n
			n2, err2 := writer.Write([]byte("\n"))
			Expect(err2).ToNot(HaveOccurred())
			Expect(n2).To(Equal(1))
			// The \n should be converted to \r\n
			Expect(buffer.String()).To(Equal("hello\r\n"))
		})

		It("handles multiple writes with mixed endings", func() {
			// Write 1: content with LF
			n1, err1 := writer.Write([]byte("line1\n"))
			Expect(err1).ToNot(HaveOccurred())
			Expect(n1).To(Equal(6))

			// Write 2: content with CRLF
			n2, err2 := writer.Write([]byte("line2\r\n"))
			Expect(err2).ToNot(HaveOccurred())
			Expect(n2).To(Equal(7))

			// Write 3: content with LF
			n3, err3 := writer.Write([]byte("line3\n"))
			Expect(err3).ToNot(HaveOccurred())
			Expect(n3).To(Equal(6))

			Expect(buffer.String()).To(Equal("line1\r\nline2\r\nline3\r\n"))
		})

		It("handles text with no newlines", func() {
			n, err := writer.Write([]byte("hello"))
			Expect(err).ToNot(HaveOccurred())
			Expect(n).To(Equal(5))
			Expect(buffer.String()).To(Equal("hello"))
		})

		It("handles consecutive LFs", func() {
			n, err := writer.Write([]byte("hello\n\nworld"))
			Expect(err).ToNot(HaveOccurred())
			Expect(n).To(Equal(12))
			Expect(buffer.String()).To(Equal("hello\r\n\r\nworld"))
		})
	})

	Describe("NewCRLFWriter", func() {
		It("returns CRLFWriter on Windows", func() {
			// This test would only be meaningful on Windows
			// but we can verify the function returns the correct type
			buf := &bytes.Buffer{}
			result := NewCRLFWriter(buf)
			// On non-Windows, it will return buf directly
			// On Windows, it will return a *CRLFWriter
			Expect(result).ToNot(BeNil())
		})
	})
})

